// In production: run these checks against your actual data warehouse (BigQuery, Snowflake, Postgres)
// via HTTP Request to your data platform's query API
const checks = [
  { table: 'events.page_views', check_type: 'freshness', description: 'Last row inserted more than 4 hours ago', threshold_hours: 4, actual_hours_since_last: 6.2, passed: false },
  { table: 'events.page_views', check_type: 'volume', description: 'Row count dropped >30% vs 7-day average', threshold_pct_drop: 30, actual_pct_drop: 41, passed: false },
  { table: 'users.accounts', check_type: 'completeness', description: 'NULL rate in email column above 2%', threshold_null_pct: 2, actual_null_pct: 0.3, passed: true },
  { table: 'billing.transactions', check_type: 'uniqueness', description: 'Duplicate transaction_id rows', threshold_duplicate_pct: 0, actual_duplicate_pct: 0, passed: true },
  { table: 'nps.responses', check_type: 'freshness', description: 'Last NPS import older than 25 hours', threshold_hours: 25, actual_hours_since_last: 18, passed: true },
  { table: 'product.feature_flags', check_type: 'completeness', description: 'NULL rate in enabled column', threshold_null_pct: 0, actual_null_pct: 0, passed: true }
];
return [{ json: { checks, product: 'ProjectFlow Analytics', checked_at: new Date().toISOString() } }];

const { checks, product, checked_at } = $input.first().json;
const failed = checks.filter(c => !c.passed);
const passed = checks.filter(c => c.passed);
const pct_pass = parseFloat(((passed.length / checks.length) * 100).toFixed(1));
const by_table = {};
checks.forEach(c => {
  if (!by_table[c.table]) by_table[c.table] = { failed: 0, passed: 0 };
  c.passed ? by_table[c.table].passed++ : by_table[c.table].failed++;
});
return [{ json: { checks, failed, by_table, product, checked_at, meta: { total: checks.length, passed: passed.length, failed_count: failed.length, pass_rate_pct: pct_pass, has_failures: failed.length > 0 } } }];

const { failed, meta: m, product, checked_at } = $input.first().json;
const failLines = failed.map(f => [
  `  [FAIL] ${f.table} — ${f.check_type.toUpperCase()}`,
  `  Check: ${f.description}`,
  f.check_type === 'freshness' ? `  Actual: ${f.actual_hours_since_last}h since last row (threshold: ${f.threshold_hours}h)` : '',
  f.check_type === 'volume' ? `  Actual drop: ${f.actual_pct_drop}% (threshold: ${f.threshold_pct_drop}%)` : '',
  f.check_type === 'completeness' ? `  Actual null rate: ${f.actual_null_pct}% (threshold: ${f.threshold_null_pct}%)` : '',
  ''
].filter(Boolean).join('\n')).join('\n');
const report = [
  `DATA QUALITY SENTINEL: ${product}`,
  `Checked: ${checked_at} | ${m.total} checks | ${m.passed} passed | ${m.failed_count} FAILED | Pass rate: ${m.pass_rate_pct}%`,
  ``,
  `FAILED CHECKS:`,
  failLines,
  `ACTION: Investigate the above tables. A >40% volume drop in events.page_views may indicate a tracking outage or ETL pipeline failure.`,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
